<?php
require_once __DIR__.'/../includes/config.php'; require_admin(); $currentId=(int)current_user()['id'];$edit=null;
if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();$action=(string)($_POST['action']??'');if($action==='save'){$id=(int)($_POST['id']??0);$name=trim((string)($_POST['name']??''));$email=strtolower(trim((string)($_POST['email']??'')));$role=(string)($_POST['role']??'customer');$password=(string)($_POST['password']??'');if($name===''||!filter_var($email,FILTER_VALIDATE_EMAIL)||!in_array($role,['admin','customer'],true)){flash('error','Data pengguna tidak valid.');}elseif($id===0&&strlen($password)<8){flash('error','Password pengguna baru minimal 8 karakter.');}else{try{if($id>0){if($id===$currentId)$role='admin';if($password!==''){$hash=password_hash($password,PASSWORD_BCRYPT);$s=db()->prepare('UPDATE users SET name=?,email=?,role=?,password=? WHERE id=?');$s->bind_param('ssssi',$name,$email,$role,$hash,$id);}else{$s=db()->prepare('UPDATE users SET name=?,email=?,role=? WHERE id=?');$s->bind_param('sssi',$name,$email,$role,$id);}}else{$hash=password_hash($password,PASSWORD_BCRYPT);$s=db()->prepare('INSERT INTO users(name,email,password,role) VALUES(?,?,?,?)');$s->bind_param('ssss',$name,$email,$hash,$role);} $s->execute();$s->close();if($id===$currentId){$_SESSION['user']['name']=$name;$_SESSION['user']['email']=$email;}flash('success','Pengguna berhasil disimpan.');}catch(Throwable $e){flash('error','Pengguna gagal disimpan. Email mungkin sudah digunakan.');}}}elseif($action==='delete'){$id=(int)($_POST['id']??0);if($id===$currentId)flash('error','Akun yang sedang digunakan tidak dapat dihapus.');else{$count=db()->prepare('SELECT COUNT(*) AS total FROM orders WHERE user_id=?');$count->bind_param('i',$id);$count->execute();$total=(int)$count->get_result()->fetch_assoc()['total'];$count->close();if($total>0)flash('error','Pengguna memiliki pesanan dan tidak dapat dihapus.');else{$s=db()->prepare('DELETE FROM users WHERE id=?');$s->bind_param('i',$id);$s->execute();$s->close();flash('success','Pengguna berhasil dihapus.');}}}redirect('admin/users.php');}
if(isset($_GET['edit'])){$id=(int)$_GET['edit'];$s=db()->prepare('SELECT id,name,email,role FROM users WHERE id=?');$s->bind_param('i',$id);$s->execute();$edit=$s->get_result()->fetch_assoc();$s->close();}
$users=db()->query('SELECT u.*,COUNT(o.id) AS order_count FROM users u LEFT JOIN orders o ON o.user_id=u.id GROUP BY u.id ORDER BY u.created_at DESC');$pageTitle='Pengguna';require __DIR__.'/admin_header.php';
?>
<div class="section-head"><div><span class="eyebrow">CRUD</span><h1>Manajemen Pengguna</h1></div></div><div class="admin-two-col"><div class="panel"><h3><?= $edit?'Edit':'Tambah' ?> Pengguna</h3><form method="post" class="form-stack"><?= csrf_field() ?><input type="hidden" name="action" value="save"><input type="hidden" name="id" value="<?= (int)($edit['id']??0) ?>"><label>Nama<input name="name" value="<?= e($edit['name']??'') ?>" required></label><label>Email<input type="email" name="email" value="<?= e($edit['email']??'') ?>" required></label><label>Role<select name="role"><option value="customer" <?= ($edit['role']??'customer')==='customer'?'selected':'' ?>>Customer</option><option value="admin" <?= ($edit['role']??'')==='admin'?'selected':'' ?>>Admin</option></select></label><label>Password <?= $edit?'<small>Kosongkan jika tidak diubah</small>':'' ?><input type="password" name="password" <?= $edit?'':'required minlength="8"' ?>></label><button class="btn btn-primary">Simpan</button><?php if($edit): ?><a class="btn btn-outline" href="<?= e(url('admin/users.php')) ?>">Batal</a><?php endif; ?></form></div><div class="panel"><h3>Daftar Pengguna</h3><div class="table-wrap"><table class="table"><thead><tr><th>Nama</th><th>Role</th><th>Pesanan</th><th>Aksi</th></tr></thead><tbody><?php while($u=$users->fetch_assoc()): ?><tr><td><strong><?= e($u['name']) ?></strong><small><?= e($u['email']) ?></small></td><td><?= e($u['role']) ?></td><td><?= (int)$u['order_count'] ?></td><td class="actions"><a class="btn btn-outline btn-sm" href="<?= e(url('admin/users.php?edit='.$u['id'])) ?>">Edit</a><?php if((int)$u['id']!==$currentId): ?><form method="post" onsubmit="return confirm('Hapus pengguna ini?')"><?= csrf_field() ?><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?= (int)$u['id'] ?>"><button class="btn btn-danger btn-sm">Hapus</button></form><?php endif; ?></td></tr><?php endwhile; ?></tbody></table></div></div></div>
<?php require __DIR__.'/admin_footer.php'; ?>
